package auth

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"net/http"
	"socialpredict/handlers"

	"socialpredict/internal/domain/boundary"
	dusers "socialpredict/internal/domain/users"
	"socialpredict/security"
	"time"

	"github.com/golang-jwt/jwt/v4"
)

// LoginUserRepository exposes only the user lookup required for login.
type LoginUserRepository interface {
	FindAuthenticatedUser(ctx context.Context, username string) (*boundary.AuthenticatedUser, error)
}

// UserClaims represents the expected structure of the JWT claims
type UserClaims struct {
	Username string `json:"username"`
	jwt.StandardClaims
}

type loginResponse struct {
	Token              string `json:"token"`
	Username           string `json:"username"`
	UserType           string `json:"usertype"`
	MustChangePassword bool   `json:"mustChangePassword"`
}

func LoginHandler(users LoginUserRepository, jwtSigningKey ...[]byte) http.HandlerFunc {
	key := currentJWTSigningKey()
	if len(jwtSigningKey) > 0 {
		key = jwtSigningKey[0]
	}
	key = cloneJWTKey(key)
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = writeLoginFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		securityService := security.NewSecurityService()

		req, err := decodeLoginRequest(r)
		if err != nil {
			_ = writeLoginFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
			return
		}

		req, err = validateAndSanitizeLogin(securityService, req)
		if err != nil {
			_ = writeLoginFailure(w, http.StatusBadRequest, handlers.ReasonValidationFailed)
			return
		}

		if users == nil {
			_ = writeLoginFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		user, loginErr := authenticateUser(r.Context(), users, req)
		if loginErr != nil {
			_ = writeLoginFailure(w, loginErr.statusCode, loginFailureReason(loginErr.statusCode))
			return
		}

		if len(key) == 0 {
			_ = writeLoginFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		tokenString, err := generateJWT(user.Username, key)
		if err != nil {
			_ = writeLoginFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		_ = writeLoginResponse(w, user, tokenString)
	}
}

func cloneJWTKey(jwtSigningKey []byte) []byte {
	if len(jwtSigningKey) == 0 {
		return nil
	}
	return append([]byte(nil), jwtSigningKey...)
}

type loginRequest struct {
	Username string `json:"username" validate:"required,min=3,max=30,username"`
	Password string `json:"password" validate:"required,min=1"`
}

func decodeLoginRequest(r *http.Request) (loginRequest, error) {
	var req loginRequest
	decoder := json.NewDecoder(io.LimitReader(r.Body, 1<<20))
	decoder.DisallowUnknownFields()
	if err := decoder.Decode(&req); err != nil {
		return loginRequest{}, fmt.Errorf("error reading request body")
	}
	if err := decoder.Decode(&struct{}{}); err != io.EOF {
		return loginRequest{}, fmt.Errorf("error reading request body")
	}
	return req, nil
}

func validateAndSanitizeLogin(securityService *security.SecurityService, req loginRequest) (loginRequest, error) {
	sanitizedUsername, err := securityService.Sanitizer.SanitizeUsername(req.Username)
	if err != nil {
		return req, fmt.Errorf("invalid input")
	}
	req.Username = sanitizedUsername

	if err := securityService.Validator.ValidateStruct(req); err != nil {
		return req, fmt.Errorf("invalid input")
	}

	return req, nil
}

type loginError struct {
	statusCode int
}

func authenticateUser(ctx context.Context, users LoginUserRepository, req loginRequest) (boundary.AuthenticatedUser, *loginError) {
	if users == nil {
		return boundary.AuthenticatedUser{}, &loginError{statusCode: http.StatusInternalServerError}
	}

	user, err := findUserByUsername(ctx, users, req.Username)
	if err != nil {
		if errors.Is(err, dusers.ErrUserNotFound) {
			return boundary.AuthenticatedUser{}, &loginError{statusCode: http.StatusUnauthorized}
		}
		return boundary.AuthenticatedUser{}, &loginError{statusCode: http.StatusInternalServerError}
	}

	if !user.CheckPasswordHash(req.Password) {
		return boundary.AuthenticatedUser{}, &loginError{statusCode: http.StatusUnauthorized}
	}

	return user, nil
}

func findUserByUsername(ctx context.Context, users LoginUserRepository, username string) (boundary.AuthenticatedUser, error) {
	if users == nil {
		return boundary.AuthenticatedUser{}, fmt.Errorf("database connection is not initialized")
	}

	user, err := users.FindAuthenticatedUser(ctx, username)
	if err != nil {
		return boundary.AuthenticatedUser{}, err
	}
	if user == nil {
		return boundary.AuthenticatedUser{}, dusers.ErrUserNotFound
	}
	return *user, nil
}

func generateJWT(username string, jwtKey []byte) (string, error) {
	if len(jwtKey) == 0 {
		return "", fmt.Errorf("missing JWT signing key")
	}

	claims := &UserClaims{
		Username: username,
		StandardClaims: jwt.StandardClaims{
			ExpiresAt: time.Now().UTC().Add(24 * time.Hour).Unix(),
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	return token.SignedString(jwtKey)
}

func writeLoginResponse(w http.ResponseWriter, user boundary.AuthenticatedUser, tokenString string) error {
	return handlers.WriteResult(w, http.StatusOK, loginResponse{
		Token:              tokenString,
		Username:           user.Username,
		UserType:           user.UserType,
		MustChangePassword: user.MustChangePassword,
	})
}

func writeLoginFailure(w http.ResponseWriter, statusCode int, reason handlers.FailureReason) error {
	return handlers.WriteFailure(w, statusCode, reason)
}

func loginFailureReason(statusCode int) handlers.FailureReason {
	switch statusCode {
	case http.StatusUnauthorized:
		return handlers.ReasonAuthorizationDenied
	default:
		return handlers.ReasonInternalError
	}
}

package app

import (
	"time"

	"gorm.io/gorm"

	// Domain services
	analytics "socialpredict/internal/domain/analytics"
	dbets "socialpredict/internal/domain/bets"
	dmarkets "socialpredict/internal/domain/markets"
	positionsmath "socialpredict/internal/domain/math/positions"
	"socialpredict/internal/domain/math/probabilities/wpam"
	dusers "socialpredict/internal/domain/users"

	// Repositories
	rbets "socialpredict/internal/repository/bets"
	rmarkets "socialpredict/internal/repository/markets"
	rusers "socialpredict/internal/repository/users"

	// Handlers
	hmarkets "socialpredict/handlers/markets"
	authsvc "socialpredict/internal/service/auth"
	configsvc "socialpredict/internal/service/config"
	"socialpredict/security"
)

// Clock interface for testability
type Clock interface {
	Now() time.Time
}

// SystemClock implements Clock using system time
type SystemClock struct{}

func (SystemClock) Now() time.Time {
	return time.Now()
}

// Container holds all the application dependencies
type Container struct {
	db            *gorm.DB
	configService configsvc.Service
	config        *configsvc.AppConfig
	clock         Clock

	// Repositories
	marketsRepo   rmarkets.GormRepository
	usersRepo     rusers.GormRepository
	analyticsRepo analytics.GormRepository
	betsRepo      rbets.GormRepository

	// Domain services
	analyticsService *analytics.Service
	marketsService   *dmarkets.Service
	usersService     *dusers.Service
	betsService      *dbets.Service
	authService      *authsvc.AuthService
	jwtSigningKey    []byte

	// Handlers
	marketsHandler *hmarkets.Handler
}

// NewContainer creates a new dependency injection container
func NewContainer(db *gorm.DB, configService configsvc.Service) *Container {
	if configService == nil {
		configService = configsvc.NewStaticService(nil)
	}

	return &Container{
		db:            db,
		configService: configService,
		config:        configService.Current(),
		clock:         SystemClock{},
	}
}

func NewContainerWithJWTSigningKey(db *gorm.DB, configService configsvc.Service, jwtSigningKey []byte) *Container {
	container := NewContainer(db, configService)
	container.jwtSigningKey = append([]byte(nil), jwtSigningKey...)
	return container
}

// InitializeRepositories sets up all repository implementations
func (c *Container) InitializeRepositories() {
	c.marketsRepo = *rmarkets.NewGormRepository(c.db)
	c.usersRepo = *rusers.NewGormRepository(c.db)
	c.betsRepo = *rbets.NewGormRepository(c.db)
}

// InitializeServices sets up all domain services with their dependencies
func (c *Container) InitializeServices() {
	// Users service depends on users repository and configuration
	securityService := security.NewSecurityService()

	wpamSeeds := wpam.Seeds{
		InitialProbability:     c.config.Economics.MarketCreation.InitialMarketProbability,
		InitialSubsidization:   c.config.Economics.MarketCreation.InitialMarketSubsidization,
		InitialYesContribution: c.config.Economics.MarketCreation.InitialMarketYes,
		InitialNoContribution:  c.config.Economics.MarketCreation.InitialMarketNo,
	}
	wpamCalculator := wpam.NewProbabilityCalculator(wpam.StaticSeedProvider{Value: wpamSeeds})
	positionProbabilityProvider := positionsmath.NewWPAMProbabilityProvider(wpamCalculator)
	positionCalculator := positionsmath.NewPositionCalculator(
		positionsmath.WithProbabilityProvider(positionProbabilityProvider),
	)

	positionCalcAdapter := analytics.NewMarketPositionCalculator(positionCalculator)
	analyticsConfig := analytics.Config{
		MaximumDebtAllowed: c.config.Economics.User.MaximumDebtAllowed,
		CreateMarketCost:   c.config.Economics.MarketIncentives.CreateMarketCost,
		InitialBetFee:      c.config.Economics.Betting.BetFees.InitialBetFee,
	}
	betsConfig := dbets.Config{
		InitialBetFee:      c.config.Economics.Betting.BetFees.InitialBetFee,
		BuySharesFee:       c.config.Economics.Betting.BetFees.BuySharesFee,
		MaxDustPerSale:     c.config.Economics.Betting.MaxDustPerSale,
		MaximumDebtAllowed: c.config.Economics.User.MaximumDebtAllowed,
	}

	c.analyticsRepo = *analytics.NewGormRepository(c.db, analytics.WithRepositoryPositionCalculator(positionCalcAdapter))
	c.analyticsService = analytics.NewService(&c.analyticsRepo, analyticsConfig, analytics.WithPositionCalculator(positionCalcAdapter))
	c.usersService = dusers.NewService(&c.usersRepo, c.analyticsService, securityService.Sanitizer)
	c.authService = authsvc.NewAuthService(c.usersService, c.jwtSigningKey)

	// Markets service depends on markets repository and users service
	marketsConfig := dmarkets.Config{
		MinimumFutureHours: c.config.Economics.MarketCreation.MinimumFutureHours,
		CreateMarketCost:   c.config.Economics.MarketIncentives.CreateMarketCost,
		MaximumDebtAllowed: c.config.Economics.User.MaximumDebtAllowed,
	}

	c.marketsService = dmarkets.NewService(
		&c.marketsRepo,
		c.usersService,
		c.clock,
		marketsConfig,
		dmarkets.WithProbabilityEngine(dmarkets.DefaultProbabilityEngine(wpamCalculator)),
	)

	c.betsService = dbets.NewService(&c.betsRepo, c.marketsService, c.usersService, betsConfig, c.clock)
}

// InitializeHandlers sets up all HTTP handlers with their service dependencies
func (c *Container) InitializeHandlers() {
	c.marketsHandler = hmarkets.NewHandler(c.marketsService, c.authService)
}

// Initialize sets up the entire dependency graph
func (c *Container) Initialize() {
	c.InitializeRepositories()
	c.InitializeServices()
	c.InitializeHandlers()
}

// GetMarketsHandler returns the markets HTTP handler
func (c *Container) GetMarketsHandler() *hmarkets.Handler {
	return c.marketsHandler
}

// GetUsersService returns the users domain service
func (c *Container) GetUsersService() *dusers.Service {
	return c.usersService
}

// GetUsersRepository returns the users repository edge for boundary-contained consumers such as login.
func (c *Container) GetUsersRepository() *rusers.GormRepository {
	return &c.usersRepo
}

// GetAnalyticsService returns the analytics domain service
func (c *Container) GetAnalyticsService() *analytics.Service {
	return c.analyticsService
}

// GetMarketsService returns the markets domain service
func (c *Container) GetMarketsService() *dmarkets.Service {
	return c.marketsService
}

// GetBetsService returns the bets domain service
func (c *Container) GetBetsService() *dbets.Service {
	return c.betsService
}

// GetAuthService returns the authentication façade
func (c *Container) GetAuthService() *authsvc.AuthService {
	return c.authService
}

// GetConfigService returns the runtime configuration service.
func (c *Container) GetConfigService() configsvc.Service {
	return c.configService
}

// BuildApplicationWithConfigService creates a fully wired application container using the runtime config service.
func BuildApplicationWithConfigService(db *gorm.DB, configService configsvc.Service) *Container {
	container := NewContainer(db, configService)
	container.Initialize()
	return container
}

func BuildApplicationWithConfigAndJWTSigningKey(db *gorm.DB, configService configsvc.Service, jwtSigningKey []byte) *Container {
	container := NewContainerWithJWTSigningKey(db, configService, jwtSigningKey)
	container.Initialize()
	return container
}

// BuildApplication preserves older call sites that still provide an owned or legacy raw config snapshot.
func BuildApplication(db *gorm.DB, config any) *Container {
	return BuildApplicationWithConfigService(db, configsvc.NewStaticService(config))
}

package adminhandlers

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"socialpredict/handlers"
	"socialpredict/handlers/authhttp"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
	configsvc "socialpredict/internal/service/config"
	"socialpredict/logger"
	"socialpredict/security"
	"strings"
)

type adminUserCreator interface {
	CreateAdminManagedUser(ctx context.Context, req dusers.AdminManagedUserCreateRequest) (*dusers.AdminManagedUserCreateResult, error)
}

func AddUserHandler(userCreator adminUserCreator, configService configsvc.Service, auth authsvc.Authenticator) func(http.ResponseWriter, *http.Request) {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		responseData, handlerErr := processAddUser(r, userCreator, configService, auth)
		if handlerErr != nil {
			_ = handlers.WriteFailure(w, handlerErr.statusCode, handlerErr.reason)
			logAddUserFailure(handlerErr)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(responseData)
		if username, ok := responseData["username"].(string); ok {
			logger.LogInfo("AddUser", "ProcessAddUser", "Created user "+username)
		}
	}
}

type handlerError struct {
	message    string
	statusCode int
	logErr     error
	reason     handlers.FailureReason
}

func processAddUser(r *http.Request, userCreator adminUserCreator, configService configsvc.Service, auth authsvc.Authenticator) (map[string]interface{}, *handlerError) {
	securityService := security.NewSecurityService()
	req, decodeErr := decodeAddUserRequest(r)
	if decodeErr != nil {
		return nil, &handlerError{
			message:    decodeErr.Error(),
			statusCode: http.StatusBadRequest,
			logErr:     decodeErr,
			reason:     handlers.ReasonInvalidRequest,
		}
	}

	if err := validateAddUserUsername(securityService, req.Username); err != nil {
		return nil, &handlerError{
			message:    "Invalid username: " + err.Error(),
			statusCode: http.StatusBadRequest,
			logErr:     err,
			reason:     handlers.ReasonValidationFailed,
		}
	}
	req.Username, _ = securityService.Sanitizer.SanitizeUsername(req.Username)

	if userCreator == nil {
		return nil, &handlerError{message: "user service unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}

	if auth == nil {
		return nil, &handlerError{message: "authentication service unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}
	if _, authErr := auth.RequireAdmin(r); authErr != nil {
		return nil, &handlerError{
			message:    authErr.Message,
			statusCode: authhttp.StatusCode(authErr),
			logErr:     errors.New(authErr.Message),
			reason:     authhttp.FailureReason(authErr),
		}
	}

	if configService == nil {
		return nil, &handlerError{message: "configuration service unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}

	appConfig := configService.Current()
	result, err := userCreator.CreateAdminManagedUser(r.Context(), dusers.AdminManagedUserCreateRequest{
		Username:              req.Username,
		InitialAccountBalance: appConfig.Economics.User.InitialAccountBalance,
	})
	if err != nil {
		return nil, addUserCreateError(err)
	}

	responseData := map[string]interface{}{
		"message":  "User created successfully",
		"username": result.Username,
		"password": result.Password,
		"usertype": result.UserType,
	}
	return responseData, nil
}

type addUserRequest struct {
	Username string `json:"username" validate:"required,min=3,max=30,username"`
}

func decodeAddUserRequest(r *http.Request) (addUserRequest, error) {
	var req addUserRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		return addUserRequest{}, fmt.Errorf("Error decoding request body")
	}
	return req, nil
}

func validateAddUserUsername(securityService *security.SecurityService, username string) error {
	if err := securityService.Validator.ValidateStruct(addUserRequest{Username: username}); err != nil {
		return err
	}
	_, err := securityService.Sanitizer.SanitizeUsername(username)
	return err
}

func addUserCreateError(err error) *handlerError {
	if errors.Is(err, dusers.ErrUserAlreadyExists) {
		validationErr := fmt.Errorf("username, display name, email, or API key already in use")
		return &handlerError{
			message:    validationErr.Error(),
			statusCode: http.StatusBadRequest,
			logErr:     validationErr,
			reason:     handlers.ReasonValidationFailed,
		}
	}

	return &handlerError{
		message:    "Failed to create user",
		statusCode: http.StatusInternalServerError,
		logErr:     err,
		reason:     handlers.ReasonInternalError,
	}
}

func logAddUserFailure(handlerErr *handlerError) {
	if handlerErr == nil || handlerErr.logErr == nil {
		return
	}

	if handlerErr.statusCode >= http.StatusInternalServerError {
		logger.LogError("AddUser", "ProcessAddUser", handlerErr.logErr)
		return
	}

	message := strings.TrimSpace(handlerErr.message)
	if message == "" {
		message = handlerErr.logErr.Error()
	}
	logger.LogWarn("AddUser", "ProcessAddUser", message)
}

