package auth

import (
	"net/http"
	"os"
	"strings"
	"sync"

	dusers "socialpredict/internal/domain/users"

	"github.com/golang-jwt/jwt/v4"
)

var (
	processJWTKeyMu sync.RWMutex
	processJWTKey   []byte
)

// ConfigureJWTSigningKey injects the runtime/bootstrap-owned JWT signing key for legacy helper call sites.
func ConfigureJWTSigningKey(jwtSigningKey []byte) {
	processJWTKeyMu.Lock()
	defer processJWTKeyMu.Unlock()
	processJWTKey = cloneJWTKey(jwtSigningKey)
}

func currentJWTSigningKey() []byte {
	processJWTKeyMu.RLock()
	defer processJWTKeyMu.RUnlock()
	if len(processJWTKey) > 0 {
		return cloneJWTKey(processJWTKey)
	}
	return []byte(strings.TrimSpace(os.Getenv("JWT_SIGNING_KEY")))
}

func getJWTKey() []byte {
	return currentJWTSigningKey()
}

func Authenticate(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Here you would verify the JWT token or session
		// If it's valid, call next.ServeHTTP to pass to the next handler
		// Otherwise, return an error
	})
}

// ValidateUserAndEnforcePasswordChange performs user validation and checks if a password change is required.
// It returns the user and any errors encountered.
func ValidateUserAndEnforcePasswordChangeGetUser(r *http.Request, svc dusers.ServiceInterface) (*dusers.User, *AuthError) {
	return ValidateUserAndEnforcePasswordChangeGetUserWithSigningKey(r, svc, currentJWTSigningKey())
}

// ValidateUserAndEnforcePasswordChangeGetUserWithSigningKey performs user validation with an injected JWT key.
func ValidateUserAndEnforcePasswordChangeGetUserWithSigningKey(r *http.Request, svc dusers.ServiceInterface, jwtSigningKey []byte) (*dusers.User, *AuthError) {
	user, authErr := validateTokenAndGetUser(r, svc, jwtSigningKey)
	if authErr != nil {
		return nil, authErr
	}

	if authErr := CheckMustChangePasswordFlag(user); authErr != nil {
		return nil, authErr
	}

	return user, nil
}

// ValidateTokenAndGetUser checks that the user is who they claim to be, and returns their information for use
func ValidateTokenAndGetUser(r *http.Request, svc dusers.ServiceInterface) (*dusers.User, *AuthError) {
	return validateTokenAndGetUser(r, svc, currentJWTSigningKey())
}

// ValidateTokenAndGetUserWithSigningKey checks that the user is who they claim to be using an injected JWT key.
func ValidateTokenAndGetUserWithSigningKey(r *http.Request, svc dusers.ServiceInterface, jwtSigningKey []byte) (*dusers.User, *AuthError) {
	return validateTokenAndGetUser(r, svc, jwtSigningKey)
}

func validateTokenAndGetUser(r *http.Request, svc dusers.ServiceInterface, jwtSigningKey []byte) (*dusers.User, *AuthError) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return nil, newAuthError(ErrorKindMissingToken)
	}
	if len(jwtSigningKey) == 0 {
		return nil, newAuthError(ErrorKindServiceUnavailable)
	}

	tokenString := strings.TrimPrefix(authHeader, "Bearer ")
	token, err := jwt.ParseWithClaims(tokenString, &UserClaims{}, func(token *jwt.Token) (interface{}, error) {
		return jwtSigningKey, nil
	})
	if err != nil {
		return nil, newAuthError(ErrorKindInvalidToken)
	}

	if claims, ok := token.Claims.(*UserClaims); ok && token.Valid {
		user, err := svc.GetUser(r.Context(), claims.Username)
		if err != nil {
			if err == dusers.ErrUserNotFound {
				return nil, newAuthError(ErrorKindUserNotFound)
			}
			return nil, newAuthError(ErrorKindUserLoadFailed)
		}
		return user, nil
	}
	return nil, newAuthError(ErrorKindInvalidToken)
}

// CheckMustChangePasswordFlag checks if the user needs to change their password
func CheckMustChangePasswordFlag(user *dusers.User) *AuthError {
	if user.MustChangePassword {
		return newAuthError(ErrorKindPasswordChangeRequired)
	}
	return nil
}

package auth

import (
	"net/http"
	"strings"

	dusers "socialpredict/internal/domain/users"
)

// Authenticator exposes the authentication operations used by HTTP handlers.
type Authenticator interface {
	CurrentUser(r *http.Request) (*dusers.User, *AuthError)
	RequireUser(r *http.Request) (*dusers.User, *AuthError)
	RequireAdmin(r *http.Request) (*dusers.User, *AuthError)
}

// AuthService provides a façade over the authentication helpers so callers can
// depend on a single injected object rather than package-level functions.
type AuthService struct {
	users         dusers.ServiceInterface
	jwtSigningKey []byte
}

// NewAuthService constructs a façade that uses the provided users service for
// token validation and password-change enforcement.
func NewAuthService(users dusers.ServiceInterface, jwtSigningKey ...[]byte) *AuthService {
	var key []byte
	if len(jwtSigningKey) > 0 {
		key = append([]byte(nil), jwtSigningKey[0]...)
	} else {
		key = currentJWTSigningKey()
	}
	return &AuthService{users: users, jwtSigningKey: key}
}

// CurrentUser returns the authenticated user, ensuring any password-change
// requirements are enforced.
func (a *AuthService) CurrentUser(r *http.Request) (*dusers.User, *AuthError) {
	return ValidateUserAndEnforcePasswordChangeGetUserWithSigningKey(r, a.users, a.jwtSigningKey)
}

// RequireUser resolves the authenticated user without checking the
// must-change-password flag.
func (a *AuthService) RequireUser(r *http.Request) (*dusers.User, *AuthError) {
	return ValidateTokenAndGetUserWithSigningKey(r, a.users, a.jwtSigningKey)
}

// RequireAdmin ensures the current user is authenticated and has admin privileges.
func (a *AuthService) RequireAdmin(r *http.Request) (*dusers.User, *AuthError) {
	user, err := a.CurrentUser(r)
	if err != nil {
		return nil, err
	}

	if strings.ToUpper(user.UserType) != "ADMIN" {
		return nil, newAuthError(ErrorKindAdminRequired)
	}

	return user, nil
}

func TestPasswordComplexityPatterns(t *testing.T) {
	securityService := security.NewSecurityService()

	patterns := []struct {
		name       string
		password   string
		shouldPass bool
	}{
		{
			name:       "Repeated characters",
			password:   "Aaaaaaaa1!",
			shouldPass: true, // Implementation doesn't check for repeated characters
		},
		{
			name:       "Sequential numbers",
			password:   "Password123!",
			shouldPass: true, // This might pass depending on implementation
		},
		{
			name:       "Keyboard patterns",
			password:   "Qwerty123!",
			shouldPass: true, // Implementation doesn't check for keyboard patterns
		},
		{
			name:       "Dictionary word base",
			password:   "Password123!",
			shouldPass: true, // Implementation doesn't check for dictionary words
		},
		{
			name:       "Random strong password",
			password:   "Kx9#mP2$vN8!",
			shouldPass: true,
		},
	}

	for _, pattern := range patterns {
		t.Run(pattern.name, func(t *testing.T) {
			_, err := securityService.Sanitizer.SanitizePassword(pattern.password)

			if pattern.shouldPass {
				if err != nil {
					t.Logf("Expected pattern '%s' to pass but got: %v", pattern.name, err)
					// Some patterns might still fail, which could be acceptable
				}
			} else {
				if err == nil {
					t.Errorf("Expected pattern '%s' to fail but validation passed", pattern.name)
				}
			}
		})
	}
}

func TestChangePasswordHandler_InvalidTokenReturnsFailureEnvelope(t *testing.T) {
	db := modelstesting.NewFakeDB(t)
	config := modelstesting.GenerateEconomicConfig()
	container := app.BuildApplicationWithConfigService(db, configsvc.NewStaticService(config))

	req := httptest.NewRequest(http.MethodPost, "/v0/changepassword", bytes.NewBufferString(`{"currentPassword":"OldPassword123","newPassword":"NewPassword123"}`))
	req.Header.Set("Authorization", "Bearer invalid.token")
	rec := httptest.NewRecorder()

	ChangePasswordHandler(container.GetUsersService()).ServeHTTP(rec, req)

	if rec.Code != http.StatusUnauthorized {
		t.Fatalf("expected status 401, got %d: %s", rec.Code, rec.Body.String())
	}

	var response struct {
		OK     bool   `json:"ok"`
		Reason string `json:"reason"`
	}
	if err := json.Unmarshal(rec.Body.Bytes(), &response); err != nil {
		t.Fatalf("decode response: %v", err)
	}

	if response.OK {
		t.Fatalf("expected ok=false")
	}
	if response.Reason != "INVALID_TOKEN" {
		t.Fatalf("expected reason INVALID_TOKEN, got %q", response.Reason)
	}
}

